SELECT measurement_id, measurement_value, measurement_inequality
FROM allele_peptide_measurements
WHERE measurement_kind = 'mass_spec' AND measurement_value < 100;

SELECT allele_name, sequence
FROM alleles
WHERE allele_id = 1;

SELECT allele_id, AVG(measurement_value) 
FROM allele_peptide_measurements 
GROUP BY allele_id;

SELECT measurement_value
FROM allele_peptide_measurements
WHERE measurement_id = 1;

SELECT allele_name, sequence
FROM alleles
WHERE allele_id > 1;

SELECT a.allele_name, apm.measurement_value
FROM alleles a
INNER JOIN allele_peptide_measurements apm ON a.allele_id = apm.allele_id;

SELECT allele_name 
FROM alleles 
WHERE class = '<specific_class>';

SELECT sequence 
FROM peptides 
WHERE length = (SELECT MIN(length) FROM peptides);

SELECT measurement_id
FROM allele_peptide_measurements
WHERE measurement_value < 50 AND measurement_type = 'qualitative';
